from typing import Iterable, Sequence, Union

import numpy as np
import numpy.typing as npt
from geosat.cloud import pyvoxels, PointCloud
from geosat.cloud.pyvoxels import (
    VoxelDict3D,
)
from geosat.cloud.tiles import PaddedTiler
from geosat.cloud.vobject import detect_vertical_objects, detect_hanging_objects
from geosat.psanp.abstractions.pipelinemetadata import PipelineMetadata
from sklearn.linear_model import RANSACRegressor

from psanp.classifiers.ground_classifier import GroundClassifier


def _compute_z_dist_to_ground_plane(
    coords: npt.NDArray[np.float64],
    ground_mask: Union[np.ndarray, Sequence[int]],
    mask: np.ndarray,
) -> npt.NDArray[np.float64]:
    """Estimate a plane from the ground points, and compute the distance between the
    points selected with ``mask`` and their vertical projection on the plane.

    .. warning::
        It is a **vertical** and not an orthogonal projection

    :param coords: A numpy array of 3D coordinates ``(N, 3)``
    :param ground_mask: The indices of the points that correspond to the true ground.
        Their values must be in ``range(0, N)``
    :param mask: A numpy mask that selects the points to use to compute the distances.
    :return: A 1D numpy array which contain as many values (< N) as the ``mask``
        selected.
    :raises ValueError: If there is not enough ground points to estimate the plane.
    """
    ransac = RANSACRegressor()
    ransac.fit(coords[ground_mask, :2], coords[ground_mask, 2])
    z_projected = ransac.predict(coords[mask, :2])
    z_dist_to_plane = np.abs(z_projected - coords[mask, 2])
    return z_dist_to_plane


def _approximate_ground(
    k: float,
    voxels: VoxelDict3D,
    vertical_min_meter: float = 0.6,
    hanging_min_gap_size: float = 0.75,
    hanging_min_dist_to_ground: float = 0.75,
) -> VoxelDict3D:
    """Easy way to find the ground

    The idea is to find every vertical & hanging objects using a low height threshold
    Then classify as ground everything that is not taken as being vertical or hanging
    """

    voxels_xy = pyvoxels.project_voxels_to_2d(voxels)

    vertical_voxels = set(
        detect_vertical_objects(
            voxels_xy, k, min_meter=vertical_min_meter, max_meter=99.9
        )
    )
    hanging_voxels = set(
        detect_hanging_objects(
            voxels_xy,
            k,
            min_gap_size=hanging_min_gap_size,
            min_dist_to_ground=hanging_min_dist_to_ground,
        )
    )
    ground_voxels = {
        voxel: indices
        for voxel, indices in voxels.items()
        if voxel not in vertical_voxels and voxel not in hanging_voxels
    }
    return ground_voxels


class UrbanGroundClassifier(GroundClassifier):
    """
    This ground classifier is an improvement to the GroundClassifier
    that produces better results in urban areas where the ground
    is concrete and mostly planar.

    It works by classifying the ground the same way the GroundClassifier does
    then finds a plan that matches the ground just found and uses that plan to
    improve the ground classification by adding or removing points to the ground
    class.
    """

    def execute_on(
        self, cloud: PointCloud, pipeline_metadata: PipelineMetadata
    ) -> Iterable[PointCloud]:
        if not cloud:
            return (cloud,)
        in_class_code = pipeline_metadata.classification_codes[self.input_class]
        ground_class_code = pipeline_metadata.classification_codes[self.output_class]
        # First pass
        voxels = pyvoxels.voxelize_cloud(
            cloud, self.gsd, mask=cloud.classification == in_class_code
        )
        ground_voxels = _approximate_ground(self.gsd, voxels)
        # ground = _extract_ground_point_indices(ground_voxels)
        ground = [i for indices in ground_voxels.values() for i in indices]
        cloud.classification[ground] = ground_class_code

        # At this point, the classification will show voxel artifacts and contain a
        # lot of noise, a second pass with plane fitting is needed

        resolution = 20.0
        tiler = PaddedTiler(
            origin=(0.0, 0.0), resolution=resolution, padding=resolution / 2.0
        )
        for tile in tiler.generate_tiles(cloud.coords[:, :2]):
            coords_in_tile = cloud.coords[tile.indices]
            tile_coords = tiler.compute_tile_coords(coords_in_tile[:, :2])
            to_modify_mask = np.all(tile_coords == tile.coord, axis=1)
            try:
                z_dist_to_ground = _compute_z_dist_to_ground_plane(
                    coords_in_tile,
                    ground_mask=cloud.classification[tile.indices] == ground_class_code,
                    mask=to_modify_mask,
                )
            except ValueError:
                continue  # Not enough points to estimate the ground plane
            indices = tile.indices[to_modify_mask]
            cloud.classification[indices[z_dist_to_ground < 0.15]] = ground_class_code
            cloud.classification[indices[z_dist_to_ground >= 1.0]] = in_class_code
        return (cloud,)
